import { component$, Slot } from "@builder.io/qwik";
import { useLocation } from "@builder.io/qwik-city";
import { categories } from "../../data/docs";

export default component$(() => {
  const loc = useLocation();

  const categorySlug = loc.params.category;
  const pageSlug = loc.params.slug;

  const activeCategory = categories.find((c) => c.slug === categorySlug);
  const activePage = activeCategory?.pages.find((p) => p.slug === pageSlug);

  return (
    <div class="docs-container">
      {/* Breadcrumb Trail */}
      <nav aria-label="breadcrumb" class="docs-breadcrumb">
        <ol>
          <li>
            <a href="/docs">Docs</a>
          </li>
          {activeCategory && (
            <li>
              <span class="separator">/</span>
              {activePage ? (
                <a href={`/docs/${activeCategory.slug}`}>{activeCategory.title}</a>
              ) : (
                <span aria-current="page">{activeCategory.title}</span>
              )}
            </li>
          )}
          {activePage && (
            <li>
              <span class="separator">/</span>
              <span aria-current="page">{activePage.title}</span>
            </li>
          )}
        </ol>
      </nav>

      <div class="docs-layout">
        {/* Sidebar Navigation */}
        <aside class="docs-sidebar">
          <nav aria-label="sidebar">
            <ul>
              {categories.map((category) => {
                const isActive = category.slug === categorySlug;
                return (
                  <li key={category.slug}>
                    <a
                      href={`/docs/${category.slug}`}
                      aria-current={isActive ? "page" : undefined}
                      class={isActive ? "active" : ""}
                    >
                      {category.title}
                    </a>
                  </li>
                );
              })}
            </ul>
          </nav>
        </aside>

        {/* Main Content Area */}
        <main class="docs-content">
          <Slot />
        </main>
      </div>
    </div>
  );
});

import { component$ } from "@builder.io/qwik";
import { categories } from "../../data/docs";

export default component$(() => {
  return (
    <>
      <h1>Documentation</h1>
      <p>Select a category below to get started:</p>
      <ul class="docs-list">
        {categories.map((category) => (
          <li key={category.slug}>
            <a href={`/docs/${category.slug}`}>{category.title}</a>
            <p>{category.pages.length} pages available</p>
          </li>
        ))}
      </ul>
    </>
  );
});

import { component$, Slot } from "@builder.io/qwik";
import { routeLoader$ } from "@builder.io/qwik-city";
import { findCategory } from "../../../data/docs";

export const useCategoryLoader = routeLoader$(async (ev) => {
  const category = findCategory(ev.params.category);
  if (!category) {
    throw ev.error(404, "Category not found");
  }
  return category;
});

export default component$(() => {
  return <Slot />;
});

import { component$ } from "@builder.io/qwik";
import { useCategoryLoader } from "./layout";

export default component$(() => {
  const categorySignal = useCategoryLoader();
  const category = categorySignal.value;

  return (
    <>
      <h1>{category.title}</h1>
      <p>Select a page from this category:</p>
      <ul class="pages-list">
        {category.pages.map((page) => (
          <li key={page.slug}>
            <a href={`/docs/${category.slug}/${page.slug}`}>{page.title}</a>
          </li>
        ))}
      </ul>
    </>
  );
});

import { component$ } from "@builder.io/qwik";
import { routeLoader$ } from "@builder.io/qwik-city";
import { findPage } from "../../../../data/docs";

export const usePageLoader = routeLoader$(async (ev) => {
  const page = findPage(ev.params.category, ev.params.slug);
  if (!page) {
    throw ev.error(404, "Page not found");
  }
  return page;
});

export default component$(() => {
  const pageSignal = usePageLoader();
  const page = pageSignal.value;

  return (
    <>
      <h1>{page.title}</h1>
      <p>{page.body}</p>
    </>
  );
});

